#include <stdio.h>
#include <stdlib.h>

int open_file_counter(const char *filename) {
    int attempts = 0;
    FILE *f = fopen(filename, "r");
    if (f != NULL) {
        char buffer[1024];
        fgets(buffer, sizeof(buffer), f);
        fclose(f);
    }
    // finally equivalent
    attempts += 1;
    return attempts;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char filename[256];
    for (int i = 0; i < T; ++i) {
        scanf("%255s", filename);
        int res = open_file_counter(filename);
        printf("%d\n", res);
    }
    return 0;
}

