#include <bits/stdc++.h>
using namespace std;

int open_file_counter(const string &filename) {
    int attempts = 0;
    ifstream file(filename);
    if (file.is_open()) {
        string line;
        getline(file, line);
        file.close();
    }
    // finally equivalent
    ++attempts;
    return attempts;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    string filename;
    for (int i = 0; i < T; ++i) {
        cin >> filename;
        cout << open_file_counter(filename) << '\n';
    }
    return 0;
}

