#!/usr/bin/env python3
import sys

def open_file_counter(filename: str) -> int:
    attempts = 0
    try:
        with open(filename, 'r') as f:
            f.readline()
    except FileNotFoundError:
        pass
    finally:
        attempts += 1
        return attempts

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        filename = data[i].strip()
        out.append(str(open_file_counter(filename)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

